CALLBACK_URL = 'http://localhost:5000/callback'  # callback URL
SCOPE = 'openid'  # scope
RESPONSE_TYPE = 'id_token'  # response type

@app.route('/')
def home():
    return "Welcome to the internal admin dashboard SSO!"

@app.route('/login')
def login():
    return redirect(f"https://{AUTH0_DOMAIN}/authorize?"
                    f"response_type={RESPONSE_TYPE}&"
                    f"client_id={CLIENT_ID}&"
                    f"redirect_uri={CALLBACK_URL}&"
                    f"scope={SCOPE}")

@app.route('/callback')
def callback():
    token = request.args.get('id_token')  # get the id_token from the redirect URL
    
    return "Received ID Token: {}".format(token)

